                item, fields=fields, using=self.db,
                returning_fields=self.model._meta.db_returning_fields,
                ignore_conflicts=ignore_conflicts,
            ))
        else:
            self._insert(item, fields=fields, using=self.db, ignore_conflicts=ignore_conflicts)
